const { ethers } = require('ethers');

async function setupProvider() {
  const provider = new ethers.providers.Web3Provider(window.ethereum);
  await provider.send('eth_requestAccounts', []);
  return provider.getSigner();
}

async function approveToken(signer, tokenAddress, spenderAddress) {
  const ERC20_ABI = [
    "function approve(address spender, uint256 amount) public returns (bool)"
  ];
  const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, signer);
  const maxUint256 = ethers.constants.MaxUint256;
  return await tokenContract.approve(spenderAddress, maxUint256);
}

async function swapTokens(signer, dexAddress, inputTokenAddress, outputTokenAddress, amountIn, amountOutMin) {
  const DEX_ABI = [
    "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)"
  ];
  const dexContract = new ethers.Contract(dexAddress, DEX_ABI, signer);
  const path = [inputTokenAddress, outputTokenAddress];
  const deadline = Math.floor(Date.now() / 1000) + 60 * 20;
  return await dexContract.swapExactTokensForTokens(amountIn, amountOutMin, path, await signer.getAddress(), deadline);
}

async function executeSwap(tokenIn, tokenOut, dexAddress, amountIn, amountOutMin) {
  const signer = await setupProvider();
  await approveToken(signer, tokenIn, dexAddress);
  const swapTx = await swapTokens(signer, dexAddress, tokenIn, tokenOut, amountIn, amountOutMin);
  console.log('Swap Transaction:', swapTx);
}

